 51→func runEnrichProspect(d *sql.DB, email string) error {
 52→	result, err := enrichpkg.Enrich(d, enrichpkg.EnrichRequest{ContactEmail: email})
 53→	if err != nil {
 54→		return err
 55→	}
 56→
 57→	if enrichFormat == "json" {
 58→		enc := json.NewEncoder(os.Stdout)
 59→		enc.SetIndent("", "  ")
 60→		return enc.Encode(result)
 61→	}
 62→
 63→	fmt.Printf("  Enrichment: %s\n", result.ContactEmail)
 64→	if len(result.FieldsFilled) > 0 {
 65→		fmt.Printf("  Filled:\n")
 66→		for f, v := range result.FieldsFilled {
 67→			fmt.Printf("    %s: %s\n", f, v)
 68→		}
 69→	}
 70→	if len(result.FieldsMissing) > 0 {
 71→		fmt.Printf("  Still missing: %v\n", result.FieldsMissing)
 72→	}
 73→	if len(result.ProvidersUsed) > 0 {
 74→		fmt.Printf("  Providers: %v\n", result.ProvidersUsed)
 75→	}
 76→	if result.Cached > 0 {
 77→		fmt.Printf("  Cached hits: %d\n", result.Cached)
 78→	}
 79→	if result.TotalCost > 0 {
 80→		fmt.Printf("  Est. cost: $%.4f\n", result.TotalCost)
 81→	}
 82→	return nil
 83→}
