 85→func runEnrichBatch(d *sql.DB, limit int) error {
 86→	results, err := enrichpkg.BatchEnrich(d, limit)
 87→	if err != nil {
 88→		return err
 89→	}
 90→
 91→	if enrichFormat == "json" {
 92→		enc := json.NewEncoder(os.Stdout)
 93→		enc.SetIndent("", "  ")
 94→		return enc.Encode(results)
 95→	}
 96→
 97→	if len(results) == 0 {
 98→		fmt.Println("  No contacts to enrich.")
 99→		return nil
100→	}
101→
102→	totalFilled := 0
103→	totalMissing := 0
104→	totalCached := 0
105→	var totalCost float64
106→	for _, r := range results {
107→		totalFilled += len(r.FieldsFilled)
108→		totalMissing += len(r.FieldsMissing)
109→		totalCached += r.Cached
110→		totalCost += r.TotalCost
111→	}
112→
113→	fmt.Printf("  Enriched %d contact(s):\n", len(results))
114→	fmt.Printf("    Fields filled: %d\n", totalFilled)
115→	fmt.Printf("    Fields missing: %d\n", totalMissing)
116→	fmt.Printf("    Cache hits: %d\n", totalCached)
117→	if totalCost > 0 {
118→		fmt.Printf("    Est. cost: $%.4f\n", totalCost)
119→	}
120→	return nil
121→}
