 56→// Backfill emails from Unipile (90 days of sent history)
 57→export const backfillEmails = action({
 58→  args: {
 59→    userId: v.string(),
 60→    unipileAccountId: v.string(),
 61→  },
 62→  handler: async (ctx, args) => {
 63→    const apiKey = process.env.UNIPILE_API_KEY;
 64→    const apiUrl = process.env.UNIPILE_API_URL;
 65→
 66→    if (!apiKey || !apiUrl) {
 67→      throw new Error("Unipile API key or URL not configured");
 68→    }
 69→
 70→    const since = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
 71→    let cursor: string | undefined;
 72→    let totalFetched = 0;
 73→
 74→    do {
 75→      const params = new URLSearchParams({
 76→        account_id: args.unipileAccountId,
 77→        folder: "SENT",
 78→        after: since,
 79→        limit: "100",
 80→      });
 81→      if (cursor) {
 82→        params.set("cursor", cursor);
 83→      }
 84→
 85→      const resp = await fetch(`${apiUrl}/api/v1/emails?${params}`, {
 86→        headers: { "X-API-KEY": apiKey },
 87→      });
 88→
 89→      if (!resp.ok) {
 90→        const error = await resp.text();
 91→        throw new Error(`Unipile email list failed: ${error}`);
 92→      }
 93→
 94→      const result = await resp.json();
 95→      const emails = result.items || result.data || [];
 96→
 97→      if (emails.length === 0) break;
 98→
 99→      // Store emails in Convex (batch)
100→      for (const email of emails) {
101→        const toEmails = (email.to || []).map(
102→          (t: any) => t.identifier || t.email || ""
103→        );
104→        const ccEmails = (email.cc || []).map(
105→          (c: any) => c.identifier || c.email || ""
106→        );
107→
108→        await ctx.runMutation(internal.unipile.storeEmail, {
109→          userId: args.userId,
110→          email: {
111→            externalId: email.id || `uni-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
112→            source: "unipile",
113→            direction: "outbound",
114→            threadId: email.thread_id || "",
115→            subject: email.subject || "",
116→            fromEmail: email.from?.identifier || "",
117→            toEmails: JSON.stringify(toEmails),
118→            ccEmails: JSON.stringify(ccEmails),
119→            date: email.date || new Date().toISOString(),
120→            snippet: email.body_plain?.substring(0, 200) || "",
121→            unipileId: email.id || "",
122→            providerId: email.provider_id
123→              ? JSON.stringify(email.provider_id)
124→              : "",
125→            unipileAccountId: args.unipileAccountId,
126→          },
127→        });
128→        totalFetched++;
129→      }
130→
131→      cursor = result.cursor || result.next_cursor;
132→    } while (cursor);
133→
134→    return { totalFetched };
135→  },
136→});
