 12→// Provider defines an enrichment data source loaded from YAML.
 13→type Provider struct {
 14→	Name           string            `yaml:"name"`
 15→	Type           string            `yaml:"provider"` // apify, apollo, http
 16→	Endpoint       string            `yaml:"endpoint,omitempty"`
 17→	ActorID        string            `yaml:"actor_id,omitempty"`
 18→	CostPerCall    float64           `yaml:"cost_per_call"`
 19→	FieldsProvided []string          `yaml:"fields_provided"`
 20→	InputType      string            `yaml:"input_type"` // email, linkedin_url, name_company, domain
 21→	InputMapping   map[string]string `yaml:"input_mapping"`
 22→	OutputMapping  map[string]string `yaml:"output_mapping"`
 23→	CacheTTL       string            `yaml:"cache_ttl"` // e.g., "168h"
 24→}
 25→
 26→// ProviderRegistry holds all loaded providers keyed by name.
 27→type ProviderRegistry struct {
 28→	providers map[string]Provider
 29→}
 30→
 31→// LoadProviders scans bundled provider YAMLs from internal/enrich/providers/
 32→// and user-defined YAMLs from .nurge/providers/. User definitions override
 33→// bundled ones by name.
 34→func LoadProviders() (*ProviderRegistry, error) {
 35→	reg := &ProviderRegistry{
 36→		providers: make(map[string]Provider),
 37→	}
 38→
 39→	// 1. Load bundled providers (currently none -- Apify/Apollo YAMLs were
 40→	// removed as dead code; enrichment now uses Convex/Unipile).
 41→	entries, err := fs.ReadDir(bundledProviders, "providers")
 42→	if err == nil {
 43→		for _, entry := range entries {
 44→			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
 45→				continue
 46→			}
 47→			data, readErr := fs.ReadFile(bundledProviders, "providers/"+entry.Name())
 48→			if readErr != nil {
 49→				continue
 50→			}
 51→			var p Provider
 52→			if err := yaml.Unmarshal(data, &p); err != nil {
 53→				continue // skip invalid bundled defs
 54→			}
 55→			if p.Name == "" {
 56→				continue
 57→			}
 58→			reg.providers[p.Name] = p
 59→		}
 60→	}
 61→
 62→	// 2. Load project-local providers from .nurge/providers/
 63→	localDir := filepath.Join(".nurge", "providers")
 64→	localEntries, err := os.ReadDir(localDir)
 65→	if err == nil { // silently skip if dir doesn't exist
 66→		for _, entry := range localEntries {
 67→			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
 68→				continue
 69→			}
 70→			data, err := os.ReadFile(filepath.Join(localDir, entry.Name()))
 71→			if err != nil {
 72→				continue
 73→			}
 74→			var p Provider
 75→			if err := yaml.Unmarshal(data, &p); err != nil {
 76→				continue
 77→			}
 78→			if p.Name == "" {
 79→				continue
 80→			}
 81→			reg.providers[p.Name] = p
 82→		}
 83→	}
 84→
 85→	return reg, nil
 86→}
 87→
 88→// GetProvider returns a provider by name, or false if not found.
 89→func (r *ProviderRegistry) GetProvider(name string) (Provider, bool) {
 90→	p, ok := r.providers[name]
 91→	return p, ok
 92→}
 93→
 94→// ProvidersForField returns all providers that can fill a given field.
 95→func (r *ProviderRegistry) ProvidersForField(field string) []Provider {
 96→	var result []Provider
 97→	for _, p := range r.providers {
 98→		for _, f := range p.FieldsProvided {
 99→			if f == field {
100→				result = append(result, p)
101→				break
102→			}
103→		}
104→	}
105→	return result
106→}
